class Solution {
public:
    int lengthOfLongestSubstring(string s) {
        unordered_map<char, int> myBiMap;

        int l = 0, r = 0;
        int count = 0;
        int max_count = 0;
        while(r < s.size()-1){
            if(myBiMap.count(s[r])){
                l = myBiMap[s[r]] +1;
                r = l;
                max_count = max(count, max_count);
                count = 0;
                myBiMap = {};
            } else{
                count++;
                myBiMap[s[r]] = r;
                r++;
            }
        }

        return max(count, max_count);

    }
};

